mapper.select:
SELECT sra.id, sra.recruitId, sra.spaceId, sra.userId, sra.applyReason, sra.applyStatus, sra.reviewMessage, sra.reviewerId, sra.reviewTime, sra.createTime, sra.editTime, sra.updateTime, u.userAccount, u.userName AS applicantName, u.userAvatar AS userAvatar, sr.title AS recruitTitle, s.spaceName, ru.userName AS reviewerName FROM space_recruit_apply sra LEFT JOIN user u ON sra.userId = u.id LEFT JOIN space_recruit sr ON sra.recruitId = sr.id LEFT JOIN space s ON sra.spaceId = s.id LEFT JOIN user ru ON sra.reviewerId = ru.id
sra.isDelete = 0
AND sra.recruitId = #{recruitId}
AND sra.spaceId = #{spaceId}
AND sra.userId = #{userId}
AND sra.applyStatus = #{applyStatus}
ORDER BY ${sortField} DESC ASC
ORDER BY sra.createTime DESC

SELECT COUNT(*)
FROM space_recruit_apply
WHERE isDelete = 0
AND applyStatus = 0

    AND spaceId = #{spaceId}


    AND recruitId = #{recruitId}
